import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as c,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as m,a1 as d,C as a}from"./framework-a4c02b8f.js";const f={},u=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/755b551842df938576f9fc2048d4a90f.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),g=d('<hr><p>在互联网上看过许多人的人生，有时看到某些人结婚生子会觉得「幸福」。这绝对不是什么坏事，前面的话也并不是讽刺。人应该向着幸福前进。</p><p>另一方面，对幸福的人的兴趣逐渐减少也是真的。「家庭的幸福」，只有在同样温暖的家庭中的人才能感受到共鸣，不是吗。看到别人家的孩子、普通的宠物、做饭的照片，只会感觉到( ´_ゝ｀)哼。</p><p>那种微妙的判断力下降是很可怕的。别人婴儿的脸看起来都一样，所以对其说「可爱」大部分都是客套话。正在给你看照片的人以前也一定在被上司展示和孩子旅行的照片的时候，内心喊过「没兴趣～！！！」吧。不对，或许，无论何时都喜欢看别人孩子照片的可能性也是存在的。如果是这样的话，和我的感性太不一样了，好可怕。</p><p>是不是因为自己太幸福了，所以产生了和他人分享幸福的话，对方也会高兴的错觉呢。我不认为自己能和这样的人正常沟通。幸福本身是没有罪的。但是否能与他们交谈或对他们感兴趣则完全是另一回事了。很遗憾，我只能把他们放入脑内的「幸福的人」文件夹之中。</p><p>或许自己有一天也会变成那种状态。可爱的恋人。温暖的家。笑容满面的孩子们。虽然未来会有许多艰难困苦，但包括这些烦恼在内，愉快而圆满的生活。看着变成那样的我，现在的我会觉得「是个有趣的人」吗？ 而且，被那样的我展示孩子的睡颜并问道：「可爱吗？」会是什么样的感觉呢。会伤心的吧。在这之上，能让对方更加感兴趣地交流的能力，也随着寂寞一起消失了吧。</p><p>作为扭曲的年轻人信任成年人的条件之一，「对方是否背负着寂寞」是很重要的。虽然有家庭但还是很哀愁的成年人也是存在的。他们一定是没有忘记与生俱来的悲伤的人。因为自己没有忘记寂寞，所以面对寂寞的年轻人，能够让他们好好地听他说话。从扭曲的年轻人的角度来看，「幸福而正确的成年人的说教」是最让人恼火的。他们因为正论无法解决的问题而苦恼，但是因为过于幸福而感觉迟钝的成年人只会说正确的话。</p><p>说正确的话和漂亮话，是一条非常轻松的道路。因为并不会说错话，只要说就完事了。随着年龄的增长，发言的责任也变得越来越重，所以会尽可能地选择说低风险的漂亮话。但是，你见过班里的坏孩子真正接受学校老师指导的时刻吗？ 他们只知道「做这样的事/说这样的话」会挨骂，而不知道对自己的错误行为进行反思、改变想法。就目前而言，双方只是互相扮演了「老师」和「学生」的角色。如果你真正地面对对方的话，我觉得是不能通过这样简单的话语解决的。小时候，他们自己也应该明白这个道理，但每当离一般的幸福越来越近时，就会忘记这样的事情。</p><p>虽然很令人悲伤，但是好像没有办法，郁闷的夜晚。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/28cf2c7d4f619d3b597a46c5d102127d.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【黏土人的玛俐与宝可梦卡牌的玛俐】我喜欢玛俐。我更喜欢她长得像大槻賢二（オーケン）和曼森（マンソン）的结合体的哥哥。她身后的宝可梦卡牌价格飙升得厉害，我都开始害怕了。我当然不会把它们卖掉，但我家的动漫商品竟然会自己变得越来越值钱，真厉害。</p></blockquote>',12);function b(x,y){const n=a("ExternalLinkIcon"),r=a("RouterLink");return c(),_("div",null,[i(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第13回／満たされて感覚が鈍ること"),o(n)])]),e("blockquote",null,[k,e("p",null,[o(r,{to:"/posts/Translate/nyalra_kb_12.html"},{default:m(()=>[t("【奈亚拉面壁自语】第12回｜关于「聪明人」的概念的思考【230207】")]),_:1})])]),g])}const C=s(f,[["render",b],["__file","nyalra_kb_13.html.vue"]]);export{C as default};
